<?php
/**
 * GLV Global Food Services — Auto-Installer
 * Upload to public_html/ and open in browser ONCE.
 * The script writes all site files then deletes itself.
 */
set_time_limit(120);
$base = __DIR__;
$files = [
  'index.html' => '',
  'huevo-proteinas.html' => '',
  'coco-aceites.html' => '',
  'granos-cereales.html' => '',
  'animales-vivos.html' => '',
  'frutas.html' => '',
  'comercio-internacional.html' => '',
  'send-email.php' => '',
];

$log = [];
foreach ($files as $name => $b64) {
    $gz   = base64_decode($b64);
    $data = gzdecode($gz);
    $dest = $base . '/' . $name;
    if (file_put_contents($dest, $data) !== false) {
        $log[] = "✓ $name (" . number_format(strlen($data)) . " bytes)";
    } else {
        $log[] = "✗ FAILED: $name";
    }
}

// Self-delete
@unlink(__FILE__);

header('Content-Type: text/html; charset=utf-8');
echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>GLV Deploy</title>
<style>body{font-family:monospace;background:#0a0a0a;color:#c9a84c;padding:2rem;}
h2{color:#fff;} .ok{color:#4caf50;} .err{color:#f44336;} .done{margin-top:2rem;padding:1rem;border:1px solid #c9a84c;border-radius:6px;}</style></head><body>
<h2>GLV Global Food Services — Deploy Complete</h2><pre>';
foreach ($log as $line) {
    $cls = str_starts_with($line, '✓') ? 'ok' : 'err';
    echo "<span class=\"$cls\">$line</span>\n";
}
echo '</pre><div class="done">✅ All files deployed. This installer has been deleted.<br>
Visit: <a href="https://glvglobalfoodservices.com" style="color:#c9a84c">glvglobalfoodservices.com</a></div>
</body></html>';
